import{j as t,c as a,b as o,ah as e}from"./chunks/framework.Br27zpCu.js";const c=JSON.parse('{"title":"How to Install Android Studio","description":"","frontmatter":{},"headers":[],"relativePath":"bagisto-native/native-integration/android/how-to-guides/install-android-studio.md","filePath":"bagisto-native/native-integration/android/how-to-guides/install-android-studio.md","lastUpdated":1773897321000}'),n={name:"bagisto-native/native-integration/android/how-to-guides/install-android-studio.md"};function l(s,i,d,r,h,p){return o(),a("div",null,[...i[0]||(i[0]=[e(`<h1 id="how-to-install-android-studio" tabindex="-1">How to Install Android Studio <a class="header-anchor" href="#how-to-install-android-studio" aria-label="Permalink to &quot;How to Install Android Studio&quot;">​</a></h1><p>Android Studio is the official integrated development environment (IDE) for building Android apps.</p><h2 id="step-1-check-system-requirements" tabindex="-1">Step 1: Check System Requirements <a class="header-anchor" href="#step-1-check-system-requirements" aria-label="Permalink to &quot;Step 1: Check System Requirements&quot;">​</a></h2><p>Before installing, ensure your computer meets the following:</p><ul><li><strong>Operating System</strong>: Windows 10+, macOS 10.14+, or Linux</li><li><strong>RAM</strong>: 8GB minimum (16GB recommended)</li><li><strong>Storage</strong>: At least 8GB of free space</li><li><strong>Java</strong>: JDK 17 or higher</li></ul><h2 id="step-2-download-android-studio" tabindex="-1">Step 2: Download Android Studio <a class="header-anchor" href="#step-2-download-android-studio" aria-label="Permalink to &quot;Step 2: Download Android Studio&quot;">​</a></h2><ol><li>Visit the <a href="https://developer.android.com/studio" target="_blank" rel="noreferrer">Android Studio website</a>.</li><li>Click <strong>Download Android Studio</strong>.</li><li>Accept the terms and conditions.</li><li>Save the installer to your computer.</li></ol><h2 id="step-3-install-android-studio" tabindex="-1">Step 3: Install Android Studio <a class="header-anchor" href="#step-3-install-android-studio" aria-label="Permalink to &quot;Step 3: Install Android Studio&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>Open the downloaded <code>.dmg</code> file.</li><li>Drag <strong>Android Studio</strong> to your Applications folder.</li><li>Open Android Studio from Applications.</li></ol><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><ol><li>Run the downloaded <code>.exe</code> installer.</li><li>Follow the installation wizard.</li><li>Choose default settings for all options.</li></ol><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><ol><li>Extract the downloaded <code>.zip</code> file.</li><li>Navigate to the <code>android-studio/bin</code> directory.</li><li>Run <code>./studio.sh</code>.</li></ol><h2 id="step-4-configure-sdk-components" tabindex="-1">Step 4: Configure SDK Components <a class="header-anchor" href="#step-4-configure-sdk-components" aria-label="Permalink to &quot;Step 4: Configure SDK Components&quot;">​</a></h2><p>When you first launch Android Studio:</p><ol><li>The <strong>SDK Manager</strong> will open automatically.</li><li>Install the following components: <ul><li><strong>Android SDK Platform</strong> (API 34)</li><li><strong>Android SDK Build-Tools</strong></li><li><strong>Android SDK Platform-Tools</strong></li><li><strong>Android Emulator</strong></li></ul></li></ol><h2 id="step-5-verify-installation" tabindex="-1">Step 5: Verify Installation <a class="header-anchor" href="#step-5-verify-installation" aria-label="Permalink to &quot;Step 5: Verify Installation&quot;">​</a></h2><p>Open a terminal and run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check if Android SDK is available</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ANDROID_HOME</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or list installed platforms</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ANDROID_HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/platforms</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./create-android-project">Create Android Project</a> - Start a new project</li><li><a href="./../android-app-setup/android-studio-setup">Android Studio Setup</a> - Configure the IDE</li></ul>`,22)])])}const g=t(n,[["render",l]]);export{c as __pageData,g as default};
